// Captures a marketing screenshot of every template mini app.
//
// Boots the Vite dev server, opens /app-preview.html?slug=<slug> for each
// entry in public/app-preview/manifest.json (generated by
// scripts/generate-template-apps.mjs at the repo root), waits for the page's
// data-preview-ready signal, and writes an element screenshot of the app frame
// to marketing/public/apps/<slug>.png (retina, 2x).
//
//   node scripts/screenshot-app-previews.mjs [--only slug1,slug2] [--out dir]

import { spawn } from "node:child_process";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { chromium } from "playwright";

const WEB = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const ROOT = path.resolve(WEB, "..");
const PORT = 5199;
const BASE = `http://localhost:${PORT}`;

const args = process.argv.slice(2);
const argValue = (flag) => {
  const i = args.indexOf(flag);
  return i >= 0 ? args[i + 1] : undefined;
};
const only = argValue("--only")?.split(",").map((s) => s.trim());
const OUT = path.resolve(argValue("--out") ?? path.join(ROOT, "marketing/public/apps"));

const manifest = JSON.parse(
  fs.readFileSync(path.join(WEB, "public/app-preview/manifest.json"), "utf8")
).filter((e) => !only || only.includes(e.slug));

fs.mkdirSync(OUT, { recursive: true });

async function waitForServer(url, timeoutMs = 60000) {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    try {
      const res = await fetch(url);
      if (res.ok) return;
    } catch {
      // still booting
    }
    await new Promise((r) => setTimeout(r, 400));
  }
  throw new Error(`Vite dev server did not come up at ${url}`);
}

const vite = spawn("npx", ["vite", "--port", String(PORT), "--strictPort"], {
  cwd: WEB,
  stdio: ["ignore", "pipe", "pipe"],
  env: { ...process.env, BROWSER: "none" }
});
vite.stderr.on("data", (d) => process.stderr.write(d));

try {
  await waitForServer(`${BASE}/app-preview.html`);
  // PLAYWRIGHT_CHROMIUM points at a system Chromium when the pinned
  // playwright browser build isn't installed (e.g. sandboxed CI images).
  const browser = await chromium.launch({
    executablePath: process.env.PLAYWRIGHT_CHROMIUM || undefined
  });
  const page = await browser.newPage({
    viewport: { width: 1120, height: 900 },
    deviceScaleFactor: 2
  });

  const failures = [];
  for (const { slug, name } of manifest) {
    try {
      await page.goto(`${BASE}/app-preview.html?slug=${slug}`, {
        waitUntil: "domcontentloaded"
      });
      await page.waitForSelector(
        '.app-preview-frame[data-preview-ready="true"], [data-preview-error]',
        { timeout: 30000 }
      );
      const errorEl = await page.$("[data-preview-error]");
      if (errorEl) {
        throw new Error((await errorEl.textContent()) ?? "preview error");
      }
      // Let layout/animations settle one frame.
      await page.waitForTimeout(150);
      const frame = await page.$(".app-preview-frame");
      await frame.screenshot({ path: path.join(OUT, `${slug}.png`) });
      console.log(`✓ ${name} → apps/${slug}.png`);
    } catch (e) {
      failures.push(`${name}: ${String(e).split("\n")[0]}`);
      console.error(`✗ ${name}: ${String(e).split("\n")[0]}`);
    }
  }

  await browser.close();
  if (failures.length > 0) {
    console.error(`\n${failures.length}/${manifest.length} screenshots failed.`);
    process.exitCode = 1;
  } else {
    console.log(`\nAll ${manifest.length} screenshots written to ${OUT}`);
  }
} finally {
  vite.kill("SIGTERM");
}
